import pymysql
from lambda_function import lambda_event, context

def lambda_handler(event, context):
    db_host = 'your-rds-host'
    db_username = 'your-db-username'
    db_password = 'your-db-password'
    db_name = 'your-db-name'

    conn = pymysql.connect(
        host=db_host,
        user=db_username,
        password=db_password,
        database=db_name
    )

    cur = conn.cursor(pymysql.cursors.DictCursor)

    search_params = event.get('queryStringParameters', {})

    query = "SELECT * FROM products"
    params = {}

    if 'name' in search_params:
        query += " WHERE name LIKE %s"
        params['%{}%'.format(search_params['name'])] = '%' + search_params['name'] + '%'

    if 'category' in search_params:
        query += " AND category = %s"
        params[search_params['category']] = search_params['category']

    if 'price_range' in search_params and ',' in search_params['price_range']:
        price_min, price_max = map(float, search_params['price_range'].split(','))
        query += " AND price BETWEEN %s AND %s"
        params[price_min] = price_min
        params[price_max] = price_max

    cur.execute(query, tuple(params.values()))

    result = cur.fetchall()

    conn.close()

    return {
        'statusCode': 200,
        'body': result
    }